




-- Resetear autoincrement para evitar conflictos de clave duplicada al insertar nuevos registros
ALTER TABLE user_entity ALTER COLUMN id_user RESTART WITH 1;
ALTER TABLE customer_entity ALTER COLUMN id_customer RESTART WITH 51;
ALTER TABLE type_tool_entity ALTER COLUMN id_type_tool RESTART WITH 51;
ALTER TABLE kardex_entity ALTER COLUMN id_kardex RESTART WITH 51;
ALTER TABLE tool_entity ALTER COLUMN id_tool RESTART WITH 325;
ALTER TABLE kardex_detail_entity ALTER COLUMN id_kardex_detail RESTART WITH 325;
